/* 转换函数：将中文文本分段匹配转换为东巴文 */
function convertToDongba(text) {
  if (!text || !text.trim()) return [];
  var results = [];
  var i = 0;
  var chars = Array.from(text);
  while (i < chars.length) {
    var matched = false;
    for (var len = Math.min(5, chars.length - i); len >= 1; len--) {
      var word = chars.slice(i, i + len).join('');
      var entry = DONGBA_DB.find(function(d) { return d.cn === word; });
      if (entry) {
        results.push({ cn: word, svg: entry.svg, en: entry.en, found: true });
        i += len;
        matched = true;
        break;
      }
    }
    if (!matched) {
      if (/[\s，。！？、；：""（）\.\,\!\?\;\:\-\—\…]/.test(chars[i])) {
        results.push({ cn: chars[i], svg: '', en: '', found: false, isPunct: true });
      } else {
        results.push({ cn: chars[i], svg: '', en: '', found: false });
      }
      i++;
    }
  }
  return results;
}